        /// </summary>
        [Input("status")]
        public Input<bool>? Status { get; set; }

        /// <summary>
        /// Last update time of the access control policy, Unix timestamp.
        /// </summary>
        [Input("updateTime")]
        public Input<int>? UpdateTime { get; set; }

        /// <summary>
        /// Number of policies in use.
        /// </summary>
        [Input("useCount")]
        public Input<int>? UseCount { get; set; }

        public ControlPolicyState()
        {
        }
        public static new ControlPolicyState Empty => new ControlPolicyState();
    }
}
